const seen = new Set();
const videos = [];

for (const item of $input.all()) {
  const data = item.json;
  if (!data.items) continue;
  for (const v of data.items) {
    const id = v.id?.videoId;
    if (!id || seen.has(id)) continue;
    const liveStatus = v.snippet?.liveBroadcastContent;
    if (liveStatus === 'live' || liveStatus === 'upcoming') continue;
    seen.add(id);
    videos.push({
      videoId: id,
      title: v.snippet.title,
      description: (v.snippet.description || '').slice(0, 400),
      channelTitle: v.snippet.channelTitle,
      publishedAt: v.snippet.publishedAt
    });
  }
}

return videos.map(v => ({ json: v }));

const allStats = $input.all();
const allMeta = $('Flatten & Deduplicate').all();

return allStats.map(item => {
  const stats = item.json.items?.[0];
  const videoId = stats?.id;
  const meta = allMeta.find(i => i.json.videoId === videoId)?.json || {};

  const dur = stats?.contentDetails?.duration || 'PT0S';
  const match = dur.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  const seconds = (parseInt(match?.[1] || 0) * 3600) +
                  (parseInt(match?.[2] || 0) * 60) +
                  (parseInt(match?.[3] || 0));

  return {
    json: {
      videoId: videoId || '',
      title: meta.title || '',
      description: meta.description || '',
      channelTitle: meta.channelTitle || '',
      publishedAt: meta.publishedAt || '',
      viewCount: parseInt(stats?.statistics?.viewCount || 0),
      likeCount: parseInt(stats?.statistics?.likeCount || 0),
      duration: dur,
      durationSeconds: seconds,
      skipVideo: seconds > 1080 || seconds < 10
    }
  };
});

const allVideos = $input.all().map(i => i.json);
allVideos.sort((a, b) => b.viewCount - a.viewCount);
const apiKey = 'YOUR_GEMINI_API_KEY';

//Change this to be relevant for the current game and describe it in-depth
const prompt = `You are analysing VEX V5 robotics competition footage for the 2025-2026 season game called Push Back.

PUSH BACK GAME DESCRIPTION: Push Back is played on a 12x12 foot field. The game elements are coloured blocks (not rings, not discs). The field contains clear vertical tubes called goals at three heights: two High Goals on each side of the field, one Mid Goal in the centre on top of the Low Goal, and one Low Goal in the centre below the Mid Goal. Robots score by pushing blocks into these tube goals. Each goal has a Control Bonus awarded to whichever alliance has more of their coloured blocks inside it. There is no climbing structure, no discs, no mobile goals, no rings, and no stakes. This is entirely different from previous VEX V5 seasons like High Stakes (2024-2025) which used rings and stakes, or Over Under (2023-2024) which used triballs.

If the footage shows rings, stakes, mobile goals, or a climbing ladder — it is NOT Push Back. If it shows VEX IQ robots — it is NOT Push Back. If unrelated to VEX robotics entirely — it is NOT Push Back.

If this is not Push Back 2025-2026 footage, respond with exactly: SKIP

If it IS Push Back footage, provide a dense technical caption of at least 400 words covering:
(1) Robot mechanisms visible — drivetrain configuration, motor count, wheel type, block-handling mechanism type and design in detail
(2) Block handling — estimated capacity, scoring speed, and which goals are being targeted
(3) Autonomous routine structure — starting position, zones targeted, blocks scored, estimated auton score
(4) Driver control strategies — cycling patterns, defensive plays, goal control tactics, endgame
(5) Any novel or competitively significant design choices — explain why each matters competitively

Be specific and technical. Every claim must be grounded in what is visible. Do not truncate your response.`;

const pushBackSignals = [
  /push.?back/i,
  /pushback/i,
];

function titleSuggestsPushBack(title) {
  return pushBackSignals.some(p => p.test(title));
}

async function geminiRequest(helpers, url, body, maxRetries = 4) {
  let delay = 5000;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await helpers.httpRequest({
        method: 'POST',
        url,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
    } catch (e) {
      const shouldRetry = e.message.includes('503') || e.message.includes('429');
      if (shouldRetry && attempt < maxRetries) {
        await new Promise(r => setTimeout(r, delay));
        delay *= 2;
        continue;
      }
      throw e;
    }
  }
}

const results = [];
let callCount = 0;

for (let i = 0; i < allVideos.length; i++) {
  const video = allVideos[i];

  if (video.skipVideo) {
    results.push({ json: { ...video, visionCaption: 'SKIPPED: too long or too short.' } });
    continue;
  }

  if (callCount >= 10) {
    results.push({ json: { ...video, visionCaption: 'Not analysed — outside top 10.' } });
    continue;
  }

  if (callCount > 0) await new Promise(r => setTimeout(r, 2000));

  try {
    const response = await geminiRequest(
      this.helpers,
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`,
      {
        contents: [{
          parts: [
            {
              fileData: {
                fileUri: `https://www.youtube.com/watch?v=${video.videoId}`,
                mimeType: 'video/mp4'
              }
            },
            {
              text: prompt + `\n\nTitle: ${video.title}\nDescription: ${video.description}`
            }
          ]
        }],
        generationConfig: {
          temperature: 0.2,
          maxOutputTokens: 8192
        }
      }
    );

    const caption = response?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || 'No caption returned.';
    const isSkip = caption === 'SKIP' || caption.toUpperCase().startsWith('SKIP');
    const forcedByTitle = titleSuggestsPushBack(video.title);

    //Filtering depending on game
    if (isSkip && !forcedByTitle) {
      //Wrong game
      results.push({ json: { ...video, visionCaption: 'SKIPPED: Gemini confirmed wrong game.' } });
      continue;
    }

    if (isSkip && forcedByTitle) {
      //Gemini says skip but force because title includes string
      results.push({ json: { ...video, visionCaption: `NOTE: Gemini returned SKIP despite Push Back title — may be a reveal/teaser without gameplay. Title: ${video.title}` } });
      callCount++;
      continue;
    }

    results.push({ json: { ...video, visionCaption: caption } });
    callCount++;

  } catch (e) {
    results.push({ json: { ...video, visionCaption: `Gemini error: ${e.message.slice(0, 200)}` } });
    callCount++;
  }
}

return results;

const videoList = $input.first().json.videoList;
const apiKey = 'YOUR_GEMINI_API_KEY';

//Always make sure to update your prompt depending on the game, as otherwise data in the final report may include stuff from older games
const systemPrompt = 'You are an expert VEX V5 Push Back competition analyst writing for a senior competitive team preparing for elimination rounds. Push Back (2025-2026) involves robots transporting coloured blocks (red or blue) around into clear tubes, which are at three heights, the high goals (2 on each side of the field), the mid goal (one in the centre on top of the low goal) and the low goal one in the centre under the mid goal) each tube has a control bonus, which is given to a team if they have the greatest number of their (red or blue) coloured blocks in it compared with the other alliances colour. There are no discs, no alliance specific scoring and no climbing. Do not reference game elements from other VEX seasons. Your audience understands the game — do not explain it. Analyse only what is grounded in the Vision Analysis fields. Every claim must reference a specific video. Be brutally specific. Vague observations have no value. Skip any video not in English or not clearly showing Push Back competition robots.';

const userPrompt = `Videos from this week:

${videoList}

Write a brutally specific weekly meta report in GitHub-flavoured Markdown. Every claim must be grounded in specific video evidence, prioritising the Vision Analysis fields where available. If a video is not in English or not clearly Push Back competition footage, skip it entirely.

Output the report body only — no title, no date header, no preamble. Start directly with the Table of Contents, then the sections.

Use this exact Table of Contents block at the very top:

## Contents
- [Executive Summary](#1-executive-summary)
- [Mechanism Analysis](#2-mechanism-analysis)
- [Autonomous Routine Trends](#3-autonomous-routine-trends)
- [Driver Control Tactics](#4-driver-control-tactics)
- [High-Value Teams and Channels](#5-high-value-teams-and-channels)
- [Novelty Flags](#6-novelty-flags)
- [Recommended Watch List](#7-recommended-watch-list)
- [Meta Trajectory](#8-meta-trajectory)

Then write each section with these exact headings (so anchor links resolve correctly):
## 1. Executive Summary
## 2. Mechanism Analysis
## 3. Autonomous Routine Trends
## 4. Driver Control Tactics
## 5. High-Value Teams and Channels
## 6. Novelty Flags
## 7. Recommended Watch List
## 8. Meta Trajectory

### Section content requirements:

**1. Executive Summary** (4-6 sentences)
What shifted in the meta this week? What is the dominant strategic or mechanical story? What should a competitive team act on immediately?

**2. Mechanism Analysis**
For each notable mechanism observed, specify:
- Exact mechanism type and configuration
- Which video(s) demonstrate it — cite the YouTube video ID exactly as shown in the VIDEO_ID tag for each video (e.g. Demonstrated in: dQw4w9WgXcQ, 3mPeTa2zAk8), not the index number in brackets
- Estimated ball capacity or cycle speed if visible
- Competitive advantage or weakness
- Whether this is emerging, established, or declining in the meta

**3. Autonomous Routine Trends**
Specific autonomous paths observed. Which zones are being prioritised? What is the highest-scoring auton structure appearing this week? Name the teams or channels demonstrating it.

**4. Driver Control Tactics**
Specific strategies observed in driver control periods. Cycle times if estimable. Defensive patterns. Endgame execution. Name specific videos.

**5. High-Value Teams and Channels**
Only include channels producing genuine competition footage or high-level technical content. For each: team number if visible, region if identifiable, what makes their content worth watching, specific video titles.

**6. Novelty Flags**
Mechanisms, strategies, or configurations not seen in previous weeks. Be specific. Explain why it matters competitively. If nothing is genuinely novel this week, say so plainly.

**7. Recommended Watch List**
Exactly 5 videos. For each: full title, channel, and a single specific sentence explaining what competitive insight it provides.

**8. Meta Trajectory**
One paragraph: where is the VEX V5 Push Back meta heading based on this week's content? What should a team build or practice before the next competition?`;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      system_instruction: { parts: [{ text: systemPrompt }] },
      contents: [{ parts: [{ text: userPrompt }] }],
      generationConfig: { temperature: 0.3, maxOutputTokens: 8192 }
    })
  });

  const analysis = response?.candidates?.[0]?.content?.parts?.[0]?.text || 'Error: no response from Gemini.';
  return [{ json: { ...($input.first().json), analysis } }];

} catch (e) {
  return [{ json: { ...($input.first().json), analysis: `Gemini error: ${e.message.slice(0, 300)}` } }];
}

const fs = require('fs');
const os = require('os');
const path = require('path');
const { execSync } = require('child_process');

//Change your filepath to where you want reports saved
const reportsDir = '/Path/To/Your/Folder';
if (!fs.existsSync(reportsDir)) fs.mkdirSync(reportsDir, { recursive: true });

const { report, filename } = $input.item.json;
const mdPath = path.join(reportsDir, filename);
const pdfPath = mdPath.replace(/\.md$/, '.pdf');

//Save markdown
fs.writeFileSync(mdPath, report, 'utf8');

//Convert to PDF
let pdfSaved = false;
let pdfError = null;
try {
  execSync(`md-to-pdf "${mdPath}"`, { timeout: 30000 });
  pdfSaved = true;
} catch (e) {
  pdfError = e.message.slice(0, 200);
}

return [{
  json: {
    saved: true,
    mdPath,
    pdfPath: pdfSaved ? pdfPath : null,
    pdfSaved,
    pdfError,
    message: pdfSaved
      ? `MD and PDF saved to ${reportsDir}`
      : `MD saved, PDF failed: ${pdfError}`
  }
}];

const allVideos = $input.all().map(i => i.json);
allVideos.sort((a, b) => b.viewCount - a.viewCount);

const d = new Date();
const day = String(d.getDate()).padStart(2, '0');
const month = String(d.getMonth() + 1).padStart(2, '0');
const year = String(d.getFullYear()).slice(-2);

const videoList = allVideos.map((v, idx) => {
  const dur = v.duration.replace('PT','').replace('H',' hr ').replace('M',' min ').replace('S',' sec');
  return `[${idx + 1}] "${v.title}" [VIDEO_ID: ${v.videoId}]\n` +
         `    Channel: ${v.channelTitle} | Views: ${v.viewCount.toLocaleString()} | Duration: ${dur}\n` +
         `    Published: ${v.publishedAt}\n` +
         `    Description: ${v.description}\n` +
         `    Vision Analysis: ${v.visionCaption || 'Not analysed'}\n`;
}).join('\n');

return [{
  json: {
    videoCount: allVideos.length,
    //Change date format here from DD-MM-YY to others if preferred
    weekOf: `${day}-${month}-${year}`,
    videoList
  }
}];
